import { useEffect, useState } from "react";
import axios from "axios";

function Book() {

  // ✅ JWT Protection
  const token = localStorage.getItem("token");
  if (!token) {
    window.location.href = "/";
  }

  const user = JSON.parse(localStorage.getItem("user"));

  const [doctors, setDoctors] = useState([]);
  const [data, setData] = useState({
    patientId: user?._id,
    doctorName: "",
    date: "",
    time: ""
  });

  // ✅ Fetch doctors
  useEffect(() => {
    axios.get("http://localhost:5000/api/users/doctors")
      .then(res => setDoctors(res.data))
      .catch(err => console.log(err));
  }, []);

  // ✅ Handle booking
  const handleBook = async () => {
    try {
      if (!data.doctorName || !data.date || !data.time) {
        return alert("Please fill all fields");
      }

      const res = await axios.post(
        "http://localhost:5000/api/appointments/book",
        data
      );

      alert(res.data.message);

    } catch (err) {
      alert(err.response?.data?.message || "Error booking appointment");
    }
  };

  return (
    <div className="layout">

      {/* Sidebar */}
      <div className="sidebar">
        <h2>🏥 MediCare</h2>
      </div>

      {/* Main */}
      <div className="main">
        <h2>📅 Book Appointment</h2>

        <div className="card-box">

          {/* Doctor Dropdown */}
          <label>Select Doctor</label>
          <select
            onChange={(e) =>
              setData({ ...data, doctorName: e.target.value })
            }
          >
            <option value="">-- Select Doctor --</option>
            {doctors.map((doc) => (
              <option key={doc._id} value={doc.name}>
                {doc.name} ({doc.specialization})
              </option>
            ))}
          </select>

          {/* Date */}
          <label>Select Date</label>
          <input
            type="date"
            onChange={(e) =>
              setData({ ...data, date: e.target.value })
            }
          />

          {/* Time Slots */}
          <label>Select Time</label>
          <div className="slots">
            {["10AM", "11AM", "12PM", "2PM", "3PM"].map((t) => (
              <button
                key={t}
                onClick={() => setData({ ...data, time: t })}
              >
                {t}
              </button>
            ))}
          </div>

          <br />

          <button onClick={handleBook}>
            Book Appointment
          </button>

        </div>
      </div>
    </div>
  );
}

export default Book;
